CREATE TABLE students (
  student_id INT PRIMARY KEY,
  name VARCHAR(50) NOT NULL,
  email VARCHAR(80) UNIQUE,
  age INT
);

-- Valid inserts
INSERT INTO students VALUES (1, 'Alice', 'alice@school.com', 20);
INSERT INTO students VALUES (2, 'Bob',   'bob@school.com',   22);
INSERT INTO students VALUES (3, 'Carol', 'carol@school.com', 21);

-- This would FAIL — duplicate primary key
-- INSERT INTO students VALUES (2, 'Dave', 'dave@school.com', 23);

-- This would FAIL — duplicate email (UNIQUE constraint)
-- INSERT INTO students VALUES (4, 'Eve', 'alice@school.com', 19);

-- Query: Show all students
SELECT * FROM students ORDER BY student_id;

-- Query: Show the PRIMARY KEY constraint definition
SELECT constraint_name, constraint_type
FROM information_schema.table_constraints
WHERE table_name = 'students';

CREATE TABLE departments (
  dept_id INT PRIMARY KEY,
  dept_name VARCHAR(50) NOT NULL
);

CREATE TABLE employees (
  emp_id INT PRIMARY KEY,
  name VARCHAR(50) NOT NULL,
  dept_id INT,
  salary DECIMAL(10,2),
  FOREIGN KEY (dept_id) REFERENCES departments(dept_id)
);

INSERT INTO departments VALUES (1,'Engineering'), (2,'Marketing'), (3,'HR');

INSERT INTO employees VALUES
  (101, 'Alice',  1, 95000),
  (102, 'Bob',    2, 65000),
  (103, 'Carol',  1, 88000),
  (104, 'Dave',   3, 55000);

-- This would FAIL — dept_id 99 doesn't exist in departments
-- INSERT INTO employees VALUES (105, 'Eve', 99, 70000);

-- Query 1: Show employees with their department names (use JOIN)
SELECT e.name, d.dept_name, e.salary
FROM employees e
JOIN departments d ON e.dept_id = d.dept_id
ORDER BY d.dept_name, e.name;

-- Query 2: Which departments have no employees?
SELECT d.dept_name
FROM departments d
LEFT JOIN employees e ON d.dept_id = e.dept_id
WHERE e.emp_id IS NULL;
